sql:
SELECT tf.*
FROM trade_flows tf
WHERE tf.year = 2010;

SELECT COUNT(*) AS confirmed_trades_count
FROM trade_flows
WHERE trade_flow_status = 'confirmed' AND year = 2022;

SELECT product_code, SUM(quantity) AS total_quantity
FROM trade_flows
GROUP BY product_code;

SELECT users.user_name, users.email
FROM users
INNER JOIN trade_flow_documents ON users.user_id = trade_flow_documents.document_uploaded_by;

SELECT SUM(trade_flows.quantity) AS total_quantity
FROM trade_flows
WHERE trade_flows.reporter = 'ReporterA';

SELECT trade_flows.product_description, quantities.quantity_name AS quantity_unit
FROM trade_flows
JOIN quantities ON trade_flows.quantity_unit = quantities.quantity_name;

SELECT DISTINCT tf.reporter, tf.partner, p.product_name
FROM trade_flows tf
INNER JOIN products p ON tf.product_code = p.product_code;

external_knowledge:
- Import refers to goods or services brought into a country from another country; 
- The time range 2010 to 2020 is used to focus on recent trade data and trends; 
- The United States is a significant player in global trade, and analyzing its imports can provide insights into its economy and international relations; 
- Trade value in USD is an important metric for assessing the economic impact of imports.

sql:
SELECT MIN(trade_value_usd) 
FROM trade_flows 
WHERE trade_flow = 'Import';
